--- mount_ufs.c_old     Sun Mar  8 13:25:13 1998
+++ mount_ufs.c Sun Mar  8 13:27:00 1998
@@ -84,7 +84,7 @@
        struct vfsconf vfc;
        int error = 0;
 #ifdef ROOTSLICE_HUNT
